    opacity: 1;
    border-left: 3px solid currentColor; /* 加粗线条 */
    background: rgba(128,128,128,0.08);
    font-weight: bold;
    padding-left: 20px;
  }

  .display {
    margin-top: 20px; padding-top: 10px;
    border-top: 1px dashed currentColor;
