  }
</style>
</head>
<body>

<div class="panel">
  <div class="header">NARRATIVE BRANCHES</div>
  <ul class="option-list">
    <li class="option-item" onclick="pick(this,'$1')">01. $1</li>
    <li class="option-item" onclick="pick(this,'$2')">02. $2</li>
    <li class="option-item" onclick="pick(this,'$3')">03. $3</li>
