<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
  body { margin: 0; padding: 10px; font-family: sans-serif; color: currentColor; background: transparent; font-size: 14px; }

  .panel {
    /* 移除整体边框，只保留内部结构 */
    padding: 5px;
  }

  .header {
    font-size: 9px; opacity: 0.5; margin-bottom: 15px; 
    letter-spacing: 1px; font-weight: 800; border-left: 3px solid currentColor;
    padding-left: 8px;
  }

  .option-list { list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: 10px; }

  .option-item {
    padding: 12px 14px;
    cursor: pointer;
    /* 卡片边框 */
    border: 1px solid currentColor;
    border-radius: 6px;
    background: rgba(128,128,128, 0.02);
    transition: transform 0.2s, background 0.2s;
    position: relative;
    overflow: hidden;
  }

  /* 装饰性序号背景 */
  .option-item::after {
    content: "●"; position: absolute; right: 10px; top: 50%; transform: translateY(-50%);
    font-size: 10px; opacity: 0.2; transition: 0.3s;
  }

  .option-item:hover {
    transform: translateY(-2px); /* 悬浮感 */
    background: rgba(128,128,128, 0.08);
    box-shadow: 2px 2px 5px rgba(0,0,0,0.1);
  }

  .option-item.selected {
    background: rgba(128,128,128, 0.15);
    border: 1px solid currentColor;
    border-left: 6px solid currentColor; /* 左侧加粗强调 */
    transform: translateY(0); /* 按下感 */
    font-weight: bold;
  }
  .option-item.selected::after {
    opacity: 1; content: "✔"; font-size: 14px;
  }

  .display {
    margin-top: 20px; text-align: center;
    font-size: 10px; opacity: 0.4; letter-spacing: 2px;
  }
</style>
</head>
<body>

<div class="panel">
  <div class="header">STORYLINE SELECTION</div>

  <ul class="option-list">
    <li class="option-item" onclick="pick(this,'$1')">$1</li>
    <li class="option-item" onclick="pick(this,'$2')">$2</li>
    <li class="option-item" onclick="pick(this,'$3')">$3</li>
    <li class="option-item" onclick="pick(this,'$4')">$4</li>
    <li class="option-item" onclick="pick(this,'$5')">$5</li>
  </ul>

  <div class="display" id="display">Select an option to proceed</div>
</div>

<script>
  let last = null;
  function pick(el, txt) {
    if(last) last.classList.remove('selected');
    el.classList.add('selected');
    last = el;
    // 简单的视觉反馈更新
    document.getElementById('display').innerText = "SELECTED & FILLED";

    try {
      const ta = window.parent.document.querySelector('#send_textarea');
      if (ta) {
        ta.value = txt;
        ta.dispatchEvent(new Event('input', { bubbles: true }));
      }
    } catch(e) {}
  }
</script>
</body>
</html>

